"Technological singularity": {
  label: "Technological Singularity",
  summary: "The technological singularity is a hypothetical future point in time when technological growth becomes uncontrollable and irreversible, resulting in unforeseeable changes to human civilization. It\'s often associated with the development of superintelligent AI that rapidly improves itself, leading to an intelligence explosion. In AI policy, this concept drives discussions around existential risk, the long-term future of humanity, and the urgency of AI safety and control mechanisms to prevent potentially catastrophic outcomes.",
  example: "A node tagged with this attribute might discuss international treaties to prevent the development of uncontrolled superintelligent AI.",
  frequency: "Appears in \"Long-term AI Safety\" nodes discussing \"existential risk and future scenarios.\"",
  links: [
    { label: "Technological singularity", url: "https://en.wikipedia.org/wiki/Technological_singularity" }
  ]
},
"Technological Singularity (Vernor Vinge, Ray Kurzweil)": {
  label: "Technological Singularity (Vernor Vinge, Ray Kurzweil)",
  summary: "This refers to the concept of the technological singularity as popularized by authors like Vernor Vinge and Ray Kurzweil. Vinge first introduced the term, describing a point where technological progress accelerates beyond human comprehension, often due to the creation of superintelligent AI. Kurzweil further developed this idea, predicting a future where AI and biotechnology lead to radical life extension and a merging of humans with machines. In AI policy, their work frames debates about the long-term implications of advanced AI, including potential existential risks and the transformation of human nature.",
  example: "A node tagged with this attribute might analyze Kurzweil\'s predictions about AI\'s impact on human longevity and consciousness.",
  frequency: "Appears in \"Future Studies\" and \"AI Ethics\" nodes discussing \"long-term AI impacts and human evolution.\"",
  links: [
    { label: "Technological singularity", url: "https://en.wikipedia.org/wiki/Technological_singularity" },
    { label: "Ray Kurzweil", url: "https://en.wikipedia.org/wiki/Ray_Kurzweil" }
  ]
},
"Technological solutionism": {
  label: "Technological Solutionism",
  summary: "Technological solutionism is the belief that every complex social or political problem has a technological solution, often overlooking the underlying human, ethical, or systemic causes. It assumes that new technologies, like AI, can fix issues that are fundamentally non-technical. In AI policy, this perspective can lead to a narrow focus on deploying AI tools without adequately addressing the root causes of problems like inequality or bias, potentially exacerbating existing issues rather than solving them.",
  example: "A node tagged with this attribute might critique the idea that AI-driven surveillance can solve crime without addressing socioeconomic factors.",
  frequency: "Appears in \"Critiques of Technology\" nodes discussing \"overreliance on AI for societal problems.\"",
  links: [
    { label: "Technological solutionism", url: "https://en.wikipedia.org/wiki/Technological_solutionism" }
  ]
},
"Technological unemployment debate (e.g., Keynes)": {
  label: "Technological Unemployment Debate (e.g., Keynes)",
  summary: "This debate concerns the idea that technological advancements, particularly automation and AI, could lead to widespread job displacement, rendering human labor obsolete in many sectors. John Maynard Keynes famously discussed this in the 1930s, calling it \"technological unemployment.\" In AI policy, this debate is crucial for understanding the economic impacts of AI, prompting discussions about job retraining programs, social safety nets like Universal Basic Income, and policies to manage the transition to an AI-driven economy.",
  example: "A node tagged with this attribute might discuss policy proposals for managing job losses due to AI automation in manufacturing.",
  frequency: "Appears in \"Labor Economics\" nodes discussing \"AI\'s impact on employment and future of work.\"",
  links: [
    { label: "Technological unemployment", url: "https://en.wikipedia.org/wiki/Technological_unemployment" },
    { label: "John Maynard Keynes", url: "https://en.wikipedia.org/wiki/John_Maynard_Keynes" }
  ]
},
